'use client'

import { useState, useCallback, ChangeEvent } from "react";
import { convertIterableToInt, convertIntToArray } from "../_common/utils";
import { useConfettiSize, poster} from "../_common/ClientUtils";
import { MAX_32_BIT_NUM, longTextFade, longDelay, backendBaseUrl } from "../_common/constants";
import Grid from "@mui/material/Grid";
import { Stack } from "@mui/material";
import Button from "@mui/material/Button";
import Fade from "@mui/material/Fade";
import HorseRiddleResults from "./HorseRiddleResults";
import PreviousRaces from "./PreviousRaces";
import TrifectaStack from "./TrifectaStack";
import HorseRiddleDescription from "./HorseRiddleDescription";
import Confetti from "react-confetti";
import Box from "@mui/material/Box";
import TopBar from "../_common/TopBar";
import HorseGridElement from "./HorseGridElement";

const HORSE_ORDER_CORRECT_CODE = 0;
const POTENTIAL_FASTER_HORSE_CODE = 1;
const DEFINITE_FASTER_HORSE_CODE = 2;
const NUM_HORSES = 25;
const RACE_LENGTH = 5;
const MAX_NUM_RACES = 15;
const NUM_BITS_PER_HORSE = 5;

const INVALID_HORSE_MSG = "Enter an integer between 1 and 25 for each position!";
const NO_DUP_HORSES_MSG = "You cannot enter the same horse in two different positions!";
const MAX_RACES_EXCEEDED_MSG = "You cannot race anymore horses! Please submit a trifecta bet or refresh the puzzle"

function HorseRiddlePage() {
  const [hasBeenReset, setHasBeenReset] = useState(false);
  const [submitLoading, setSubmitLoading] = useState(false);
  const [raceLoading, setRaceLoading] = useState(false);
  const [randSeed, setRandSeed] = useState(Math.floor(Math.random() * MAX_32_BIT_NUM));
  const [confetti, setConfetti] = useState(false);
  const [currentRace, setCurrentRace] = useState<number[]>([]);
  const [finishedRaces, setFinishedRaces] = useState<number[]>([]);
  const [correctAns, setCorrectAns] = useState(false);
  const [wrongReason, setWrongReason] = useState("");
  const [fastestHorses, setFastestHorses] = useState([-1, -1, -1]);
  const [confettiWidth, confettiHeight] = useConfettiSize();

  const resetPuzzle = useCallback(() => {
    setCurrentRace([]);
    setFinishedRaces([]);
    setCorrectAns(false);
    setConfetti(false);
    setWrongReason("");
    setFastestHorses([-1, -1, -1]);
    setHasBeenReset(true);
    setRaceLoading(false);
    setSubmitLoading(false);
    randomizeSeed();
  }, []);

  const addRemoveHorseToRace = (horseIdx: number) => {
    if (currentRace.includes(horseIdx)) {
      removeHorseFromRace(horseIdx);
    } else if (!currentRace.includes(horseIdx) && currentRace.length < RACE_LENGTH) {
      setCurrentRace((currentRace) => [...currentRace, horseIdx]);
      if ((currentRace.length == RACE_LENGTH - 1) && (finishedRaces.length >= MAX_NUM_RACES * RACE_LENGTH)) { 
        setWrongReason(MAX_RACES_EXCEEDED_MSG);
      }
    }
  };

  const removeHorseFromRace = (horseIdx: number) => {
    setCurrentRace((currentRace) =>
      currentRace.filter((idx) => idx != horseIdx)
    );
  };

  const validateTrifectaBet = () => {
    if (trifectaBetFilled) {
      if (fastestHorses.some((position) => position > NUM_HORSES || position < 1)) {
        return INVALID_HORSE_MSG;
      }
      if (fastestHorses[0] == fastestHorses[1] || 
        fastestHorses[1] == fastestHorses[2] ||
        fastestHorses[2] == fastestHorses[0]) {
        return NO_DUP_HORSES_MSG;
      }
    }
    return "";
  };

  const updateFastestHorses = (horsePos: number, horseVal: number) => {
    setFastestHorses([...fastestHorses.slice(0, horsePos), horseVal, ...fastestHorses.slice(horsePos + 1)]);
  }

  const handleTrifectaChange = (e: ChangeEvent<HTMLInputElement>, horsePos: number) => {
    const intsOnly = e.target.value.replace(/[^0-9]/g, "");
    e.target.value = intsOnly;
    intsOnly.length < 1 ? updateFastestHorses(horsePos, -1) : updateFastestHorses(horsePos, +intsOnly);
  };

  const submitRace = async () => {
    setRaceLoading(true);
    let submittedHorsesInt = convertIterableToInt(currentRace, NUM_BITS_PER_HORSE);
    const raceResponse = await poster(
      `puzzles/horseRiddle/raceHorses`,
      {
        randSeed,
        submittedHorsesInt,
      }
    );

    let intRes = parseInt(raceResponse);
    let horseOrder = convertIntToArray(intRes, NUM_BITS_PER_HORSE, RACE_LENGTH);
    setCurrentRace([]);
    setFinishedRaces([...finishedRaces, ...horseOrder.reverse()]);
    setWrongReason("");
    setRaceLoading(false);
  };

  const checkAnswer = async () => {
    setSubmitLoading(true);
    let horsesToSubmit = fastestHorses.map((num) => num - 1).reverse();
    let fastestHorsesInt = convertIterableToInt(horsesToSubmit, NUM_BITS_PER_HORSE);
    
    const submittedRaces: number[] = [];
    const numRaces = finishedRaces.length / RACE_LENGTH;
    for (let i = 0; i < numRaces; i++) {
      const raceHorses = finishedRaces.slice(i * RACE_LENGTH, (i + 1) * RACE_LENGTH).reverse();
      const encodedRace = convertIterableToInt(raceHorses, NUM_BITS_PER_HORSE);
      submittedRaces.push(encodedRace);
    }

    const checkResponse = (await poster(
      `puzzles/horseRiddle/checkHorseRiddleAnswer`,
      {
        randSeed,
        fastestHorsesInt,
        submittedRaces,
        numRaces
      }
    ));
    
    let intRes = parseInt(checkResponse);
    let resVec = convertIntToArray(intRes, NUM_BITS_PER_HORSE, 3).reverse();

    switch (resVec[0]) {
      case HORSE_ORDER_CORRECT_CODE:
        setCorrectAns(true);
        break;
      case DEFINITE_FASTER_HORSE_CODE:
        setWrongReason(`With the current setup of races, horse ${resVec[1]} is for sure faster than horse ${resVec[2]}!`);
        break;
      case POTENTIAL_FASTER_HORSE_CODE:
        if (fastestHorses.indexOf(resVec[1]) != 0 && fastestHorses.indexOf(resVec[1]) < fastestHorses.indexOf(resVec[2])) {
          setWrongReason(`With the current setup of races, horse ${resVec[2]} could be faster than horse ${resVec[1]}!`);
        }
        else {
          setWrongReason(`With the current setup of races, horse ${resVec[1]} could be faster than horse ${resVec[2]}!`);
        }
        break;
      default:
        setWrongReason("Something has gone terribly wrong. Please refresh the page!");
    }
    setSubmitLoading(false);
  };

  const randomizeSeed = () => {
    setRandSeed(Math.floor(Math.random() * MAX_32_BIT_NUM));
  }

  let trifectaBetFilled = !fastestHorses.includes(-1);
  let trifectaErrorMessage = validateTrifectaBet();
  
  return (
    <>
      <TopBar
        text="Envelope #2: Horse Trifecta"
        isPuzzlePage={true}
        resetFunc={resetPuzzle}
      />
      {confetti && <Confetti width={confettiWidth} height={confettiHeight} />}
      <HorseRiddleDescription />
      {!correctAns && (
        <Fade
          in={true}
          mountOnEnter
          unmountOnExit
          timeout={longTextFade}
          style={{transitionDelay: hasBeenReset ? 0+"ms" : longDelay+"ms"}}
        >
          <Box
            sx={{
              display: "flex",
              justifyContent: "space-between",
              flexDirection: "row",
              width: 'var(--pageWidthPercent)',
              position: "relative",
              mb: "1vh"
            }}
          >
            <Stack direction={{sm: "column", md: "row"}}>
              <Box
                sx={{
                  display: "flex",
                  flexDirection: "column",
                  width: "100%",
                  position: "relative",
                  mb: "1vh",
                }}
              >
                Select 5 horses to race!
                <Grid
                  container
                  columnSpacing={2}
                  rowSpacing={1}
                  columns={5}
                  direction="row"
                  sx={{
                    mt: "1vh",
                    display: "flex",
                    width: "100%",
                  }}
                >
                  {[...Array(NUM_HORSES)].map((_, idx) => (
                    <HorseGridElement
                      key={idx}
                      horseNumber={idx + 1}
                      selected={currentRace.includes(idx)}
                      onClick={() => addRemoveHorseToRace(idx)}
                    />
                  ))}
                </Grid>
              </Box>
              <Box
                sx={{
                  display: "flex",
                  alignItems: "center",
                  flexDirection: "column",
                  flexGrow: 1,
                  width: "100%",
                  position: "relative",
                  mb: {
                    xs: "3em", 
                    md: "1em"
                  },
                  minHeight: {
                    xs: "30em",
                    md: "0em"
                  }
                }}
              >
                <Box
                  sx={{
                    mt: {
                      sm: "2em",
                      md: "0em"
                    },
                    display: "flex",
                    alignItems: "center",
                    flexDirection: "column",
                    width: "100%",
                    minHeight: "8.5em", 
                  }}
                >
                  Current Race:
                  <Grid
                    container
                    spacing={1}
                    columns={5}
                    direction="row"
                    sx={{
                      display: "flex",
                      width: "80%",
                      mt: "1vh",
                    }}
                  >
                    {currentRace.map((horseIdx, idx) => (
                      <HorseGridElement
                        key={idx}
                        horseNumber={horseIdx + 1}
                        onClick={() => removeHorseFromRace(horseIdx)}
                        selected = {false}
                      />
                    ))}
                  </Grid>
                <Box
                  sx={{
                    display: "flex",
                    flexDirection: "column",
                    width: "90%",
                    justifyContent: "center",
                    alignItems: "center",
                    position: "absolute",
                    bottom: "0",
                  }}
                >
                  <Box
                    sx={{
                      display: "flex",
                      width: "100%",
                      justifyContent: "center",
                      position: "relative",
                      mb: "2vh",
                    }}
                  >
                    <p>
                      {trifectaErrorMessage.length === 0? wrongReason : trifectaErrorMessage}
                    </p>
                  </Box>
                  <TrifectaStack handleTrifectaChange={handleTrifectaChange} />
                  <Button
                    variant="contained"
                    disabled={!trifectaBetFilled || trifectaErrorMessage !== ""}
                    loading = {submitLoading}
                    onClick={checkAnswer}
                  >
                    Place Trifecta Bet
                  </Button>
                </Box>
              </Box>
                <Button
                  variant="contained"
                  onClick={() => submitRace()}
                  loading = {raceLoading}
                  disabled={currentRace.length != 5 || (finishedRaces.length >= MAX_NUM_RACES * RACE_LENGTH)}
                >
                  Race Horses!
                </Button>
              </Box>
              <PreviousRaces
                finishedRaces={finishedRaces}
                MAX_NUM_RACES={MAX_NUM_RACES}
                RACE_LENGTH={RACE_LENGTH}
              />
            </Stack>
          </Box>
        </Fade>
      )}
        {correctAns && (
          <HorseRiddleResults
            numRaces={finishedRaces.length / RACE_LENGTH}
            setConfetti={setConfetti}
          />
        )}
    </>
  );
}

export default HorseRiddlePage;